enum TokenType {
    IDENTIFIER,
    KEYWORD,
    NUMBER,
    STRING,
    OPERATOR,
    DELIMITER
};

struct Token {
    TokenType type;
    string lexeme;
    int line;
    int column;
};

Token lexer(string input) {
    vector<Token> tokens;
    int i = 0;
    while (i < input.length()) {
        if (isspace(input[i])) { i++; continue; }
        if (isalpha(input[i])) {
            string word;
            while (isalnum(input[i]))
                word += input[i++];
            tokens.push_back(classify(word));
        } else if (isdigit(input[i])) {
            string num;
            while (isdigit(input[i]))
                num += input[i++];
            tokens.push_back({NUMBER, num});
        } else {
            tokens.push_back({OPERATOR, string(1, input[i++])});
        }
    }
    return tokens;
}

// Recursive Descent Parser (LL)
bool parse_expr() {
    if (parse_term()) {
        while (lookahead == PLUS || lookahead == MINUS) {
            match(lookahead);
            parse_term();
            // build tree node
        }
        return true;
    }
    return false;
}

bool parse_term() {
    if (parse_factor()) {
        while (lookahead == TIMES || lookahead == DIVIDE) {
            match(lookahead);
            parse_factor();
        }
        return true;
    }
    return false;
}
